const feedbacks = [
  // Positive
  "The app is easy to use and very intuitive.",
  "Delivery was faster than expected. Great job!",
  "Excellent service — I’ll definitely recommend it.",
  "I love the product quality; totally worth the price.",
  "Thank you for resolving my issue quickly.",
  "Your loyalty program is fantastic!",
  "Chat support was friendly and helpful.",
  "Everything went smoothly — very satisfied.",
  "I appreciate the eco-friendly packaging.",
  "Great experience overall, keep it up.",

  // Negative
  "Customer support took too long to respond.",
  "The payment process failed multiple times.",
  "The color of the item didn’t match the photo online.",
  "Received a damaged package and no one replied to my email.",
  "Prices are too high compared to competitors.",
  "The website layout is confusing on mobile.",
  "The new update made the app crash constantly.",
  "It’s annoying that I can’t cancel my order online.",
  "Product description was inaccurate.",
  "I expected better quality for the price.",

  // Neutral
  "The app works fine, but nothing special.",
  "Product arrived as described.",
  "Support was okay, not great but not terrible.",
  "The checkout process was average.",
  "Delivery took the expected time."
];

// Generate current timestamp with a small random offset (for realism)
return feedbacks.map((text, i) => {
  const now = new Date();
  const offsetMinutes = Math.floor(Math.random() * 60 * 24 * 5); // within 5 days
  const timestamp = new Date(now.getTime() - offsetMinutes * 60000).toISOString();

  return {
    json: {
      feedback: text,
      timestamp: timestamp
    }
  };
});
